.Magnetic2DVisualizer {
/*        overflow-y: auto; */
        overflow: visible;
        width: auto;
        height: auto;
}
.scaling-svg {
    object-fit: contain;
    height: auto;
    max-height: 50vh;
    width: auto;
    max-width: 100%;
    left: 0; 
    top: 0;
}
.scaling-svg-container {
    display: flex;
    justify-content: center;
    align-items: center;
    max-height: 50vh;
}
.plot-loading {
    opacity: 0.3;
    filter: brightness(0.5);
    transition: opacity 0.2s ease, filter 0.2s ease;
}
.loading-overlay {
    position: absolute;
    top: 50%;
    left: 50%;
    transform: translate(-50%, -50%);
    z-index: 10;
    pointer-events: none;
}
.loading-spinner {
    height: auto;
    max-width: 100px;
}

/* Zoom Modal Styles */
.zoom-modal-overlay {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    display: flex;
    justify-content: center;
    align-items: center;
    z-index: 9999;
}
.zoom-modal-overlay-bg {
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    opacity: 0.5;
    pointer-events: none;
}
.zoom-modal-content {
    border-radius: 8px;
    padding: 20px;
    width: 90vw;
    height: 90vh;
    position: relative;
    display: flex;
    flex-direction: column;
}
.zoom-modal-close {
    position: absolute;
    top: 10px;
    right: 10px;
    background: none;
    border: none;
    font-size: 1.5rem;
    cursor: pointer;
    z-index: 1;
}
.zoom-modal-close:hover {
    opacity: 0.7;
}
.zoom-modal-image {
    flex: 1;
    display: flex;
    justify-content: center;
    align-items: center;
    min-height: 0;
    overflow: hidden;
}
.zoom-modal-image svg {
    max-width: 100%;
    max-height: 100%;
    object-fit: contain;
}
